#include <iostream>
#include <vector>
#include <queue>
#include <limits.h>
using namespace std;
int main(){
    int n=5;
    vector<vector<pair<int,int>>> g(n);
    g[0].push_back({1,2});
    g[0].push_back({2,4});
    g[1].push_back({2,1});
    g[1].push_back({3,7});
    vector<int> dist(n,INT_MAX);
    dist[0]=0;
    priority_queue<pair<int,int>,vector<pair<int,int>>,greater<pair<int,int>>> pq;
    pq.push({0,0});
    while(!pq.empty()){
        auto [d,u]=pq.top();pq.pop();
        if(d>dist[u]) continue;
        for(auto [v,w]:g[u]){
            if(dist[u]+w<dist[v]){
                dist[v]=dist[u]+w;
                pq.push({dist[v],v});
            }
        }
    }
    for(int x:dist) cout<<x<<" ";
    return 0;
}

#include <iostream>
#include <vector>
#include <queue>
using namespace std;
int main(){
    int n=4,m=4;
    vector<vector<int>> grid(n,vector<int>(m,0));
    grid[0][0]=1;
    queue<pair<int,int>> q;
    q.push({0,0});
    int dx[4]={1,-1,0,0};
    int dy[4]={0,0,1,-1};
    while(!q.empty()){
        auto [x,y]=q.front();q.pop();
        for(int i=0;i<4;i++){
            int nx=x+dx[i],ny=y+dy[i];
            if(nx>=0&&ny>=0&&nx<n&&ny<m&&grid[nx][ny]==0){
                grid[nx][ny]=1;
                q.push({nx,ny});
            }
        }
    }
    cout<<"done";
    return 0;
}

