#include <iostream>
#include <vector>
using namespace std;
int main(){
    vector<int> coins={1,2,5};
    int target=5;
    vector<int> dp(target+1,0);
    dp[0]=1;
    for(int c:coins){
        for(int i=c;i<=target;i++){
            dp[i]+=dp[i-c];
        }
    }
    cout<<dp[target];
    return 0;
}
